class Solution:
    def clumsy(self, n: int) -> int:
        if n == 1:
            return 1
        stack = [n, n-1]
        ops = ['*', '/', '+', '-']
        op_idx = 0
        for i in range(n-2, 0, -1):
            if ops[op_idx] in ['*', '/']:
                curr_op = ops[op_idx]
                op_idx = (op_idx + 1) % 4
                if curr_op == '*':
                    stack[-1] *= i
                else:
                    stack[-1] //= i
            else:
                stack.append(i)
                stack.append(ops[op_idx])
                op_idx = (op_idx + 1) % 4
        while len(stack) > 1:
            if stack[1] == '+':
                stack[0] += stack[2]
                stack = stack[3:]
            else:
                stack[0] -= stack[2]
                stack = stack[3:]
        return stack[0]
